#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <time.h>

uint8_t g_function(uint8_t a, uint8_t b, uint8_t x) {
    uint8_t temp = (a + b + x) & 0xFF;
    return ((temp << 2) | (temp >> 6)) & 0xFF;
}

uint32_t f_function(uint32_t input_val) {
    uint8_t x[4], y[4];
    for (int i = 0; i < 4; i++) {
        x[i] = input_val & 0xFF;
        input_val >>= 8;
    }
    y[2] = g_function(x[3] ^ x[2], x[1] ^ x[0], 1);
    y[3] = g_function(x[3], y[2], 0);
    y[1] = g_function(x[1] ^ x[0], y[2], 0);
    y[0] = g_function(x[0], y[1], 1);
    uint32_t output = 0;
    for (int i = 0; i < 4; i++) output |= (uint32_t)y[i] << (8*i);
    return output;
}

int main() {
    srand(time(NULL));
    uint32_t cnt[32] = {0};
    for (int i = 0; i < 1000000; i++) {
        uint32_t in = ((uint32_t)rand()<<16) ^ rand();
        uint32_t out = f_function(in);
        // Check all possible linear masks
        for (int mask = 1; mask < 32; mask++) {
            uint32_t inmask = 0, outmask = 0;
            // compute parity of bits selected by mask in input and output
            uint32_t tmp = in & ((mask & 1 ? 0xFF : 0) | (mask & 2 ? 0xFF00 : 0) | (mask & 4 ? 0xFF0000 : 0) | (mask & 8 ? 0xFF000000 : 0));
            uint32_t tmp2 = out & ((mask & 16 ? 0xFF : 0) | (mask & 32 ? 0xFF00 : 0) | (mask & 64 ? 0xFF0000 : 0) | (mask & 128 ? 0xFF000000 : 0));
            // Not good, let's do bit-level.
        }
        // Simpler: check XOR of all input bits vs XOR of all output bits
        uint32_t in_parity = __builtin_parity(in);
        uint32_t out_parity = __builtin_parity(out);
        if (in_parity == out_parity) cnt[0]++; else cnt[1]++;
        // Check byte-wise XOR
        uint8_t in_bytes[4], out_bytes[4];
        for (int j=0;j<4;j++) {in_bytes[j]=(in>>(8*j))&0xFF; out_bytes[j]=(out>>(8*j))&0xFF;}
        uint8_t in_xor = in_bytes[0]^in_bytes[1]^in_bytes[2]^in_bytes[3];
        uint8_t out_xor = out_bytes[0]^out_bytes[1]^out_bytes[2]^out_bytes[3];
        if (in_xor == out_xor) cnt[2]++; else cnt[3]++;
    }
    printf("Parity match: %u / 1000000\n", cnt[0]);
    printf("Byte XOR match: %u / 1000000\n", cnt[2]);
    return 0;
}
