uint64_t encrypt(uint64_t plaintext, uint32_t key[4]) {
    uint32_t left = (uint32_t)(plaintext >> 32);
    uint32_t right = (uint32_t)(plaintext & 0xFFFFFFFF);
    right ^= left;
    for (int r = 0; r < 4; r++) {
        uint32_t mixed = f_function(right ^ key[r]);
        uint32_t temp = right;
        right = left ^ mixed;
        left = temp;
    }
    left ^= right;
    return ((uint64_t)right << 32) | left;
}

uint64_t decrypt_ct(uint64_t ciphertext, uint32_t key[4]) {
    uint32_t left = (uint32_t)(ciphertext & 0xFFFFFFFF);
    uint32_t right = (uint32_t)(ciphertext >> 32);
    left ^= right;
    for (int r = 3; r >= 0; r--) {
        uint32_t temp = left;
        left = right;
        uint32_t mixed = f_function(temp ^ key[r]);
        right = temp;
        left ^= mixed;
    }
    right ^= left;
    return ((uint64_t)left << 32) | right;
}

