uint8_t g_function(uint8_t a, uint8_t b, uint8_t x) {
    uint8_t temp = (a + b + x) & 0xFF;
    return ((temp << 2) | (temp >> 6)) & 0xFF;
}

uint8_t ror2(uint8_t v) { return ((v >> 2) | (v << 6)) & 0xFF; }

// G_inv_a: given result and b, recover a
// G(a,b,x) = ROL2((a+b+x) mod 256)
// So a = ROR2(result) - b - x (mod 256)
uint8_t g_inv_a(uint8_t result, uint8_t b, uint8_t x) {
    uint8_t temp = ror2(result);
    return (temp - b - x) & 0xFF;
}

uint32_t f_function(uint32_t input_val) {
    uint8_t x[4], y[4];
    for (int i = 0; i < 4; i++) { x[i] = input_val & 0xFF; input_val >>= 8; }
    y[2] = g_function(x[3] ^ x[2], x[1] ^ x[0], 1);
    y[3] = g_function(x[3], y[2], 0);
    y[1] = g_function(x[1] ^ x[0], y[2], 0);
    y[0] = g_function(x[0], y[1], 1);
    uint32_t output = 0;
    for (int i = 0; i < 4; i++) output |= (uint32_t)y[i] << (8 * i);
    return output;
}

uint32_t f_inv(uint32_t output_val) {
    uint8_t y[4], x[4];
    for (int i = 0; i < 4; i++) { y[i] = output_val & 0xFF; output_val >>= 8; }
    x[0] = g_inv_a(y[0], y[1], 1);
    uint8_t x1_xor_x0 = g_inv_a(y[1], y[2], 0);
    x[1] = x[0] ^ x1_xor_x0;
    x[3] = g_inv_a(y[3], y[2], 0);
    uint8_t x3_xor_x2 = g_inv_a(y[2], x1_xor_x0, 1);
    x[2] = x[3] ^ x3_xor_x2;
    uint32_t result = 0;
    for (int i = 0; i < 4; i++) result |= (uint32_t)x[i] << (8 * i);
    return result;
