void ht_clear() {
    memset(ht_bucket, -1, sizeof(ht_bucket));
    ht_count = 0;
}

void ht_add(uint32_t diff, uint32_t k0_seed) {
    uint32_t idx = diff % HT_SIZE;
    ht_table[ht_count].diff = diff;
    ht_table[ht_count].k0 = k0_seed;
    ht_table[ht_count].next = ht_bucket[idx];
