    y[3]=g_function(x[3],y[2],0);
    y[1]=g_function(x[1]^x[0],y[2],0);
    y[0]=g_function(x[0],y[1],1);
    uint32_t o=0;
    for(int i=0;i<4;i++)o|=(uint32_t)y[i]<<(8*i);
    return o;
}
uint32_t expand(uint32_t k){return k^(k<<16)^(k*12345);}
uint64_t encrypt_pt(uint64_t pt, uint32_t key[4]) {
    uint32_t l=(uint32_t)(pt>>32),r=(uint32_t)(pt&0xFFFFFFFF);
    r^=l;
    for(int i=0;i<4;i++){uint32_t m=f_function(r^key[i]);uint32_t t=r;r=l^m;l=t;}
    l^=r;
    return ((uint64_t)r<<32)|l;
}
int main() {
