    int ok=0,tot=0;
    uint64_t pt,ct;
    while(fscanf(f1,"%lu",&pt)==1 && fscanf(f2,"%lu",&ct)==1){tot++;if(encrypt_pt(pt,key)==ct)ok++;else printf("FAIL %d\n",tot);}
    fclose(f1);fclose(f2);
