    FILE *f3=fopen("/app/pairs.txt","r");
    int pok=0;
    for(int i=0;i<32;i++){uint64_t p,c;if(fscanf(f3,"%lu %lu",&p,&c)!=2)break;if(encrypt_pt(p,key)==c)pok++;}
    fclose(f3);
    printf("Pairs verified: %d/32\n",pok);
